```csharp
Console.Write("Âge : ");
int age = int.Parse(Console.ReadLine());
Console.Write("Étudiant ? (oui/non) : ");
bool estEtudiant = Console.ReadLine().ToLower() == "oui";

double tarif = age switch
{
    < 6 => 0,
    >= 6 and <= 12 => 2000,
    >= 13 and <= 59 => 5000,
    >= 60 => 3000
};

if (age >= 13 && age <= 59 && estEtudiant)
    tarif *= 0.8; // réduction 20%

Console.WriteLine($"Montant à payer : {tarif} FCFA");
```

